// Read PDF binary directly and base64-encode it for Gemini.
// This avoids the broken extractFromFile PDF node that requires standardFontDataUrl config.
let binaryPropertyName = 'attachment_0';
if ($input.item.binary && !$input.item.binary[binaryPropertyName]) {
  if ($input.item.binary['data']) {
    binaryPropertyName = 'data';
  } else {
    const keys = Object.keys($input.item.binary);
    if (keys.length > 0) {
      binaryPropertyName = keys[0];
    }
  }
}
const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
return [{
  json: {
    base64Pdf: binaryBuffer.toString('base64'),
    ocr_fallback_triggered: false
  }
}];

