/* Normalization & Matching Node Code */
// 1. Normalization Helpers
function normalizeVendorName(name) {
  if (!name) return "";
  return name.toLowerCase().replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, "").replace(/\b(pvt ltd|private limited|ltd|limited|llc|inc|corp|corporation|gmbh|co)\b/g, "").replace(/\s+/g, " ").trim();
}

function normalizeCurrency(currency) {
  if (!currency) return null;
  const cleaned = currency.trim().toUpperCase();
  if (cleaned === "$" || cleaned === "USD") return "USD";
  if (cleaned === "â‚¹" || cleaned === "INR" || cleaned === "RS") return "INR";
  if (cleaned === "â‚¬" || cleaned === "EUR") return "EUR";
  return cleaned;
}

function normalizeAmount(value) {
  if (value === null || value === undefined) return 0.00;
  if (typeof value === "string") {
    const cleaned = value.replace(/[^\d.-]/g, "");
    const parsed = parseFloat(cleaned);
    return isNaN(parsed) ? 0.00 : Math.round(parsed * 100) / 100;
  }
  return typeof value === "number" ? Math.round(value * 100) / 100 : 0.00;
}

function normalizeQuantity(value) {
  if (value === null || value === undefined) return 0;
  if (typeof value === "string") {
    const cleaned = value.replace(/[^\d.-]/g, "");
    const parsed = parseFloat(cleaned);
    return isNaN(parsed) ? 0 : parsed;
  }
  return typeof value === "number" ? value : 0;
}

function normalizeDate(value) {
  if (!value) return null;
  const str = String(value).trim();
  const match = str.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})/);
  if (match) return `${match[1]}-${match[2].padStart(2, '0')}-${match[3].padStart(2, '0')}`;
  try {
    const d = new Date(str);
    if (isNaN(d.getTime())) return null;
    if (str.includes("Z") || str.includes("T")) {
      return d.toISOString().split("T")[0];
    } else {
      return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    }
  } catch {
    return null;
  }
}

// 2. Parse AI response - Gemini now always gets the PDF directly as base64
let geminiRaw;
try {
  geminiRaw = $node["Gemini AI Extraction"].json.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Gemini AI Extraction failed: ' + e.message);
}
const parsed = JSON.parse(geminiRaw.replace(/```json\n?|```/g, "").trim());

// Normalize Extracted
const extracted = {
  vendor_name: parsed.vendor_name ? parsed.vendor_name.trim() : null,
  vendor_id: parsed.vendor_id ? parsed.vendor_id.trim() : null,
  purchase_order_number: parsed.purchase_order_number ? parsed.purchase_order_number.trim() : null,
  invoice_number: parsed.invoice_number ? parsed.invoice_number.trim() : null,
  invoice_date: normalizeDate(parsed.invoice_date),
  due_date: normalizeDate(parsed.due_date),
  currency: normalizeCurrency(parsed.currency),
  net_amount: normalizeAmount(parsed.net_amount),
  tax_amount: normalizeAmount(parsed.tax_amount),
  gross_amount: normalizeAmount(parsed.gross_amount),
  confidence_score: parseFloat(parsed.confidence_score) || 0.00,
  extraction_warnings: Array.isArray(parsed.extraction_warnings) ? parsed.extraction_warnings : [],
  ocr_used: parsed.ocr_used === true || parsed.ocr_used === 'true' || false,
  low_confidence_reason: parsed.low_confidence_reason || null,
  missing_critical_fields: (() => {
    const missing = [];
    if (!parsed.invoice_number) missing.push('invoice_number');
    if (!parsed.invoice_date) missing.push('invoice_date');
    if (!parsed.vendor_name) missing.push('vendor_name');
    if (!parsed.gross_amount) missing.push('gross_amount');
    return missing.length > 0 ? missing.join(', ') : '';
  })(),
  line_items: (parsed.line_items || []).map(l => ({
    line_number: parseInt(l.line_number) || 0,
    sku: l.sku ? l.sku.trim() : null,
    description: l.description ? l.description.trim() : "",
    quantity: normalizeQuantity(l.quantity),
    unit_price: normalizeAmount(l.unit_price),
    tax_rate: normalizeQuantity(l.tax_rate),
    line_net_amount: normalizeAmount(l.line_net_amount),
    line_tax_amount: normalizeAmount(l.line_tax_amount),
    line_gross_amount: normalizeAmount(l.line_gross_amount)
  }))
};

return {
  extracted
};

const invoiceId = $node["Store Invoice in NocoDB"].json.id;
const lineItems = $node["Call Matching Service"].json.validation.line_items || [];
return lineItems.map(item => ({
  json: {
    invoices: invoiceId,
    line_number: item.line_number,
    sku: item.sku,
    description: item.description,
    quantity: item.quantity,
    unit_price: item.unit_price,
    tax_rate: item.tax_rate,
    line_net_amount: item.line_net_amount,
    line_tax_amount: item.line_tax_amount,
    line_gross_amount: item.line_gross_amount,
    matched_po_line_id: item.matched_po_line_id,
    match_status: item.match_status,
    match_notes: item.match_notes
  }
}));

const invoiceId = $node["Store Invoice in NocoDB"].json.id;
const results = $node["Call Matching Service"].json.validation.results || [];
const poNumber = $node["Call Matching Service"].json.po ? $node["Call Matching Service"].json.po.po_number : null;
return results.map(item => ({
  json: {
    invoices: invoiceId,
    po_number: poNumber,
    field_name: item.fieldName || item.field_name,
    rule_category: item.ruleCategory || item.rule_category,
    invoice_value: String(item.invoiceValue !== undefined ? item.invoiceValue : (item.invoice_value || "")),
    po_value: String(item.poValue !== undefined ? item.poValue : (item.po_value || "")),
    match_status: item.matchStatus || item.match_status,
    severity: item.severity,
    rule_id: item.ruleId || item.rule_id,
    message: item.message
  }
}));

const crypto = require('crypto');

for (const item of $input.all()) {
  let binaryPropertyName = 'attachment_0';
  if (!item.binary || !item.binary[binaryPropertyName]) {
    if (item.binary && item.binary['data']) {
      binaryPropertyName = 'data';
    }
  }

  if (item.binary && item.binary[binaryPropertyName]) {
    const binaryData = item.binary[binaryPropertyName];
    const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
    const hash = crypto.createHash('sha256').update(binaryBuffer).digest('hex');

    item.json.attachmentHash = hash;
    item.json.binaryPropertyName = binaryPropertyName;
    item.json.filename = binaryData.fileName || 'invoice.pdf';
  } else {
    item.json.attachmentHash = null;
    item.json.binaryPropertyName = 'data';
    item.json.filename = 'invoice.pdf';
  }
}

return $input.all();

const poLookup = $node["NocoDB PO Lookup"].json.list || [];
const poRaw = poLookup[0] || null;
const poLineItems = $node["NocoDB PO Line Items Lookup"].json.list || [];
const vendorLookup = $node["NocoDB Vendor Lookup"].json.list || [];
const existingInvoices = $node["NocoDB Invoices Lookup"].json.list || [];
const attachmentHash = $node["Compute Attachment Hash"].json.attachmentHash;

// Extract vendor aliases
let vendorAliases = [];
if (vendorLookup[0] && vendorLookup[0].vendor_aliases) {
  try {
    vendorAliases = typeof vendorLookup[0].vendor_aliases === 'string' 
      ? JSON.parse(vendorLookup[0].vendor_aliases) 
      : vendorLookup[0].vendor_aliases;
  } catch (e) {
    vendorAliases = [];
  }
}

const po = poRaw ? {
  id: poRaw.id,
  po_number: poRaw.po_number,
  vendor_id: poRaw.vendor_id,
  vendor_name_snapshot: poRaw.vendor_name_snapshot,
  currency: poRaw.currency,
  approval_status: poRaw.approval_status,
  approved_net_amount: parseFloat(poRaw.approved_net_amount) || 0.00,
  approved_tax_amount: parseFloat(poRaw.approved_tax_amount) || 0.00,
  approved_gross_amount: parseFloat(poRaw.approved_gross_amount) || 0.00,
  remaining_amount: parseFloat(poRaw.remaining_amount) || 0.00,
  tolerance_percent: parseFloat(poRaw.tolerance_percent) || 2.00,
  tolerance_amount: parseFloat(poRaw.tolerance_amount) || 100.00,
  line_items: poLineItems.map(item => ({
    id: item.id,
    line_number: parseInt(item.line_number) || 0,
    sku: item.sku,
    description: item.description,
    quantity: parseFloat(item.quantity) || 0.0,
    unit_price: parseFloat(item.unit_price) || 0.00,
    tax_rate: parseFloat(item.tax_rate) || 0.00,
    line_net_amount: parseFloat(item.line_net_amount) || 0.00,
    line_tax_amount: parseFloat(item.line_tax_amount) || 0.00,
    line_gross_amount: parseFloat(item.line_gross_amount) || 0.00
  }))
} : null;

const options = {
  existingInvoices,
  attachmentHash,
  vendorAliases,
  multiplePOsFound: poLookup.length > 1
};

return {
  invoice: $node["Normalize Extracted JSON"].json.extracted,
  po,
  options
};

// Pull the ORIGINAL pdf binary (Extract PDF Text drops it), base64 encode for Gemini inline_data.
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
return [{
  json: {
    base64Pdf: buffer.toString('base64'),
    ocr_fallback_triggered: true
  }
}];

